<?php
/**
 * 品牌資源（NewPay logo）。
 *
 * 為什麼內嵌成 data URI 而不放實體圖檔：admin/ 與根目錄的 .htaccess 都是
 * 白名單制（只放行特定 .php），實體的 logo.png 會被 deny all 擋成 403。
 * 內嵌成 data URI 就不必動白名單、也少一個 HTTP 請求。
 * 來源：android/app_icon_source.png，用 System.Drawing 縮成 96×96 PNG。
 */
if (!defined('NEWPAY_FAVICON')) {
    define('NEWPAY_FAVICON', 'data:image/png;base64,');
}
